import "./RecipeDetails.css";
import { useEffect, useState } from "react";
import axios from "axios";
import { useParams, useNavigate } from "react-router-dom";

export default function RecipeDetails() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [recipe, setRecipe] = useState(null);

  useEffect(() => {
    const token = localStorage.getItem("token");

    if (!token) {
      alert("Please login first ❌");
      navigate("/login");
      return;
    }

    axios
      .get(`http://127.0.0.1:8000/api/recipes/${id}/`, {
        headers: {
          Authorization: `Token ${token}`,
        },
      })
      .then((res) => {
        setRecipe(res.data);
      })
      .catch((err) => {
        console.error("Recipe details error:", err);
        alert("Failed to load recipe ❌");
      });
  }, [id, navigate]);

  if (!recipe) return <h3>Loading...</h3>;

  return (
    <div className="recipe-details">
      <h2>{recipe.title}</h2>

      <img
        src={
          recipe.image
            ? `http://127.0.0.1:8000${recipe.image}`
            : "/default-food.jpg"
        }
        alt={recipe.title}
      />

      <div className="details-box">
        <p><strong>Ingredients:</strong></p>
        <p>{recipe.ingredients}</p>

        <p><strong>Steps:</strong></p>
        <p>{recipe.steps}</p>

        <p>⏱ Cooking Time: {recipe.cooking_time} mins</p>
        <p>🔥 Difficulty: {recipe.difficulty}</p>
        <p>👁 Views: {recipe.view_count}</p>
      </div>
    </div>
  );
}
